import { getOrderlyEnvConfig } from "./environment";

export function getOffChainDomain(chainId: number | string) {
  return {
    name: "Orderly",
    version: "1",
    chainId: Number(chainId),
    verifyingContract: "0xCcCCccccCCCCcCCCCCCcCcCccCcCCCcCcccccccC",
  };
}

export function getOnChainDomain(chainId: number) {
  return {
    name: "Orderly",
    version: "1",
    chainId,
    verifyingContract: getOrderlyEnvConfig().verifyingContract,
  };
}

